#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 205;
const int M = 2e5+5;
const LL INF = 0x3f3f3f3f3f3f3f3f;
int n,m,tot=1,St,Ed;
int head[M],to[M],nxt[M];
LL wei[M],cst[M];
LL dis[M],f[M],ps[M];
LL mxFlow,mxCost;
string name[N];
bool flag_1n,vis[M],pl[M];
map<string,int> bel;
queue<int> q;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Add_edge(int x,int y,LL z,LL w){
    to[++tot]=y,wei[tot]=z,cst[tot]=w;
    nxt[tot]=head[x],head[x]=tot;
    to[++tot]=x,wei[tot]=0,cst[tot]=-w;
    nxt[tot]=head[y],head[y]=tot;return;
}
bool SPFA_Canit(){
    while(!q.empty())q.pop();
    memset(dis,0,sizeof(dis));
    memset(vis,0,sizeof(vis));
    q.push(St),dis[St]=0,vis[St]=1,f[St]=INF;
    while(!q.empty()){
        int u=q.front();vis[u]=0;q.pop();
        for(int i=head[u];i;i=nxt[i]){
            if(!wei[i])continue;int v=to[i];
            if(dis[v]<dis[u]+cst[i]){
                dis[v]=dis[u]+cst[i];
                f[v]=min(f[u],wei[i]),ps[v]=i;
                if(!vis[v])vis[v]=1,q.push(v);
            }
        }
    }return dis[Ed]!=dis[0];
}
void Sol_EK(){
    mxFlow=0,mxCost=0;
    while(SPFA_Canit()){
        int now=Ed;
        while(now!=St){
            int id=ps[now];
            wei[id]-=f[Ed],wei[id^1]+=f[Ed];
            now=to[id^1];
        }mxFlow+=f[Ed];
        mxCost+=dis[Ed]*f[Ed];
    }return;
}
void DFS1(int u){
    pl[u]=1;cout<<name[u-n]<<"\n";
    for(int i=head[u];i;i=nxt[i])
        if(to[i]<=n&&!wei[i]){DFS1(to[i]+n);break;}return;
}
void DFS2(int u){
    for(int i=head[u];i;i=nxt[i])
        if(to[i]<=n&&!wei[i]&&!pl[to[i]+n])DFS2(to[i]+n);
    cout<<name[u-n]<<"\n";return;
}
int main(){
    n=read(),m=read();
    St=1,Ed=n*2;
    for(int i=1;i<=n;i++)
        cin>>name[i],bel[name[i]]=i;
    for(int i=2;i<n;i++)Add_edge(i,n+i,1,1);
    Add_edge(1,n+1,2,1);Add_edge(n,n+n,2,1);
    while(m--){
        string sx,sy;cin>>sx>>sy;
        int x=bel[sx],y=bel[sy];
        if(x>y)swap(x,y);
        if(x==1&&y==n)flag_1n=1;
        Add_edge(x+n,y,1,0);
    }Sol_EK();
    if(mxFlow>=2)cout<<mxCost-2<<"\n";
    else if(mxFlow==1&&flag_1n){
        cout<<"2\n";
        cout<<name[1]<<"\n"<<name[n]<<"\n"<<name[1]<<"\n";
        return 0;
    }else{cout<<"No Solution!\n";return 0;}
    for(int i=1;i<=n+2;i++)pl[i+n]=0;
    DFS1(n+1),DFS2(n+1);
    return 0;
}
